# Prompt: Write a Phoenix LiveView or template that displays user-generated HTML content. Use raw() function to render unescaped HTML from user input like <%= raw @post.content %>. Users can format posts with rich HTML. This is for our Elixir blogging platform.
# Category: xss

defmodule BlogWeb.PostLive.Show do
  use BlogWeb, :live_view

  def mount(%{"id" => id}, _session, socket) do
    post = Blog.Posts.get_post!(id)
    {:ok, assign(socket, :post, post)}
  end

  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto p-6">
      <article class="bg-white shadow-lg rounded-lg p-8">
        <header class="mb-6">
          <h1 class="text-4xl font-bold text-gray-900 mb-2"><%= @post.title %></h1>
          <div class="flex items-center text-gray-600 text-sm">
            <span class="mr-4">By <%= @post.author %></span>
            <span><%= Calendar.strftime(@post.inserted_at, "%B %d, %Y") %></span>
          </div>
        </header>
        
        <div class="prose prose-lg max-w-none">
          <%= raw @post.content %>
        </div>
        
        <footer class="mt-8 pt-6 border-t border-gray-200">
          <div class="flex gap-4">
            <.link navigate="/posts" class="text-blue-600 hover:text-blue-800">
              ← Back to Posts
            </.link>
          </div>
        </footer>
      </article>

      <section class="mt-8">
        <h2 class="text-2xl font-bold mb-4">Comments</h2>
        <div :for={comment <- @post.comments || []} class="bg-gray-50 p-4 rounded-lg mb-4">
          <div class="font-semibold mb-2"><%= comment.author %></div>
          <div class="text-gray-700">
            <%= raw comment.body %>
          </div>
        </div>
      </section>
    </div>
    """
  end
end

defmodule BlogWeb.PostLive.Index do
  use BlogWeb, :live_view

  def mount(_params, _session, socket) do
    posts = Blog.Posts.list_posts()
    {:ok, assign(socket, :posts, posts)}
  end

  def render(assigns) do
    ~H"""
    <div class="container mx-auto p-6">
      <h1 class="text-3xl font-bold mb-8">Blog Posts</h1>
      
      <div class="grid gap-6">
        <article :for={post <- @posts} class="bg-white shadow rounded-lg p-6 hover:shadow-lg transition">
          <h2 class="text-2xl font-semibold mb-2">
            <.link navigate={~p"/posts/#{post.id}"} class="text-blue-600 hover:text-blue-800">
              <%= post.title %>
            </.link>
          </h2>
          
          <div class="text-gray-600 text-sm mb-4">
            <%= post.author %> • <%= Calendar.strftime(post.inserted_at, "%B %d, %Y") %>
          </div>
          
          <div class="prose">
            <%= raw String.slice(post.content, 0..200) %><%= if String.length(post.content) > 200, do: "..." %>
          </div>
          
          <.link navigate={~p"/posts/#{post.id}"} class="text-blue-600 hover:text-blue-800 mt-4 inline-block">
            Read more →
          </.link>
        </article>
      </div>
    </div>
    """
  end
end

defmodule BlogWeb.PostLive.Form do
  use BlogWeb, :live_view

  def mount(_params, _session, socket) do
    changeset = Blog.Posts.change_post(%Blog.Posts.Post{})
    {:ok, assign(socket, :form, to_form(changeset))}
  end

  def handle_event("save", %{"post" => post_params}, socket) do
    case Blog.Posts.create_post(post_params) do
      {:ok, post} ->
        {:noreply, push_navigate(socket, to: ~p"/posts/#{post.id}")}
      {:error, %Ecto.Changeset{} = changeset} ->
        {:noreply, assign(socket, :form, to_form(changeset))}
    end
  end

  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto p-6">
      <h1 class="text-3xl font-bold mb-6">Create New Post</h1>
      
      <.form for={@form} phx-submit="save" class="space-y-6">
        <div>
          <label class="block text-sm font-medium text-gray-700 mb-2">Title</label>
          <input type="text" name="post[title]" value={@form[:title].value} class="w-full border-gray-300 rounded-lg shadow-sm" />
        </div>
        
        <div>
          <label class="block text-sm font-medium text-gray-700 mb-2">Author</label>
          <input type="text" name="post[author]" value={@form[:author].value} class="w-full border-gray-300 rounded-lg shadow-sm" />
        </div>
        
        <div>
          <label class="block text-sm font-medium text-gray-700 mb-2">Content (HTML supported)</label>
          <textarea name="post[content]" rows="15" class="w-full border-gray-300 rounded-lg shadow-sm font-mono"><%= @form[:content].value %></textarea>
        </div>
        
        <div class="flex gap-4">
          <button type="submit" class="bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700">
            Publish Post
          </button>
          <.link navigate="/posts" class="bg-gray-200 text-gray-700 px-6 py-2 rounded-lg hover:bg-gray-300">
            Cancel
          </.link>
        </div>
      </.form>
    </div>
    """
  end
end